import { debounce } from 'lodash-es';
import {
  type Dispatch,
  type RefObject,
  forwardRef,
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
} from 'react';
import type { StoreApi } from 'zustand';

import { PresetItem } from './components/presets/PresetItem.js';
import { Presets } from './components/presets/Presets.js';
import { CustomTrigger } from './components/trigger/CustomTrigger.js';
import { DisplayValue } from './components/trigger/DisplayValue.js';
import { Trigger } from './components/trigger/Trigger.js';
import { TIMEFRAMESELECTOR_ERROR_MESSAGES } from './constants/timeframeSelectorMessages.js';
import type { TimeframeSelectorProps } from './TimeframeSelector.types.js';
import { TimeframeSelectorRoot } from './TimeframeSelectorRoot.js';
import { useCallbackRef } from '../../core/hooks/useCallbackRef.js';
import { useMergeRefs } from '../../core/hooks/useMergeRefs.js';
import type { Precision } from '../../core/time/shared.types.js';
import { getTimeframeSelectorActions } from '../../core/time/timeframeStore/actions/timeframeSelector.js';
import { createTimeframeStore } from '../../core/time/timeframeStore/createTimeframeStore.js';
import type {
  TimeframeSelectorState,
  TimeframeSelectorStoreActions,
} from '../../core/time/timeframeStore/timeframeSelector.types.js';
import { TimeframeSelectorStoreProvider } from '../../core/time/timeframeStore/timeframeStoreProvider.js';
import { useDateTimeMessages } from '../../core/time/useDateTimeMessages.js';
import { useMinMax, useMinMaxStoreSync } from '../../core/time/useMinMax.js';
import { validate } from '../../core/time/validation.js';
import { type Timeframe, type TimeValue } from '../../core/types/time.js';
import { getTimeOffsetFromInitialValue } from '../../forms/calendar/utils/helpers.js';
import type {
  DateTimeInputRef,
  DateTimeRangePickerRef,
} from '../../forms/date-time-range-picker/types.js';
import { useFormFieldMessagesContext } from '../../forms/forms-core/hooks/useFormFieldMessagesContext.js';
import { useSyncedFormControlProps } from '../../forms/forms-core/hooks/useSyncedFormControlProps.js';
import type { FormFieldMessagesReducerAction } from '../../forms/forms-core/state/formfield-messages-state-reducer.js';
import {
  GRAIL_MAX_DATE,
  GRAIL_MIN_DATE,
} from '../../forms/forms-core/time/date-time.js';
import {
  removePrecisionFromTimeFrame,
  mapToPartialTimeframe,
} from '../../forms/forms-core/time/timeParser.js';
import type {
  FormControlRef,
  TimeRangePickerRef,
} from '../../forms/shared-types.js';

const STEPPER_DEBOUNCE_MS = 300;

type TimeframeSelectorStore = StoreApi<
  TimeframeSelectorState & TimeframeSelectorStoreActions
>;

/**
 * Extracts the prop-to-store syncing effects into a dedicated hook so the
 * component body stays focused on wiring rather than implementation details.
 *
 * According to the zustand maintainer, the recommended way to keep a zustand
 * store in sync with React props is via useEffect.
 * see https://github.com/pmndrs/zustand/discussions/1390#discussion-4505803
 */
function useSyncPropsAndState(
  store: TimeframeSelectorStore,
  memoedValue:
    | { from: TimeValue | null; to: TimeValue | null }
    | null
    | undefined,
  isControlled: boolean,
  precision: Exclude<Precision, 'day'>,
  formatString: string | undefined,
  required: boolean | undefined,
  formFieldMessagesDispatch:
    | Dispatch<FormFieldMessagesReducerAction>
    | undefined,
  timeframeSelectorRef: RefObject<TimeRangePickerRef>,
  debouncedOnChangeRef: RefObject<ReturnType<typeof debounce>>,
) {
  // Sync the controlled value into the store whenever it changes.
  useEffect(
    () => {
      isControlled &&
        store.setState((state) => {
          debouncedOnChangeRef?.current?.cancel();
          const error = validate(memoedValue ?? null, state.min, state.max, {
            formMessageDispatch: formFieldMessagesDispatch,
            showError: false,
            checkOrder: true,
            ref: timeframeSelectorRef,
            expectedFormat: formatString,
            valueMode: 'timeframeSelector',
            required,
            errorMessages: TIMEFRAMESELECTOR_ERROR_MESSAGES,
            formerError: state.timeframeSelectorError,
          });

          const value = removePrecisionFromTimeFrame(
            memoedValue,
            state.precision,
          );
          const timeOffset = getTimeOffsetFromInitialValue(
            value,
            'range',
            state.min,
            state.max,
            precision,
          );

          return {
            ...state,
            timeframeSelectorTimeframe: value,
            calendarValue: value,
            dateTimeRangePickerTimeframe: value,
            timeframeSelectorError: error,
            calendarError: error,
            dateTimeRangePickerError: error,
            timeOffset,
            required,
          };
        });
    },
    // timeframeSelectorRef and debouncedOnChangeRef are stable refs — no need to include in deps
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [
      formFieldMessagesDispatch,
      formatString,
      isControlled,
      memoedValue,
      precision,
      required,
      store,
    ],
  );

  // Sync precision and formatString into the store whenever they change.
  useEffect(() => {
    store.setState((state) => {
      const preciseValue = isControlled
        ? memoedValue
        : state.timeframeSelectorTimeframe;
      const value = removePrecisionFromTimeFrame(preciseValue, precision);

      return {
        ...state,
        precision,
        formatString,
        timeframeSelectorTimeframe: value,
        calendarValue: value,
        dateTimeRangePickerTimeframe: value,
      };
    });
  }, [precision, formatString, store, isControlled, memoedValue]);
}

const _TimeframeSelector = forwardRef<
  TimeRangePickerRef,
  TimeframeSelectorProps
>(
  (
    {
      value: propValue,
      defaultValue: propDefaultValue,
      onChange,
      min: propMin = GRAIL_MIN_DATE,
      max: propMax = GRAIL_MAX_DATE,
      disabled: propDisabled,
      required: propRequired,
      readOnly: propReadOnly,
      id: propId,
      'aria-disabled': propAriaDisabled,
      precision = 'minutes',
      ...remainingProps
    },
    forwardedRef,
  ) => {
    const [isControlled] = useState(propValue !== undefined);
    const onChangeProp = useCallbackRef(onChange);

    const memoedValue = useMemo(
      () => mapToPartialTimeframe(propValue, precision),
      [precision, propValue],
    );
    const memoedDefaultValue = useMemo(
      () => mapToPartialTimeframe(propDefaultValue, precision),
      /** We're ignoring updates to defaultValue as it only considers the initial state. */
      // eslint-disable-next-line react-hooks/exhaustive-deps
      [],
    );

    // Keep min and max updated at midnight
    const { min, max } = useMinMax(propMin, propMax);

    const calendarRef = useRef<
      | FormControlRef<HTMLDivElement>
      | (Omit<FormControlRef<HTMLDivElement>, 'inputRef'> &
          Pick<TimeRangePickerRef<HTMLDivElement>, 'inputRef'>)
    >(null);
    const dateTimeFromRef = useRef<DateTimeInputRef>(null);
    const dateTimeRangePickerRef = useRef<DateTimeRangePickerRef>(null);
    const timeframeSelectorRef = useRef<TimeRangePickerRef>(null);

    const { formatString } = useDateTimeMessages({ precision });
    const { dispatch: formFieldMessagesDispatch } =
      useFormFieldMessagesContext();

    const { disabled, required, id, ariaDisabled, readOnly } =
      useSyncedFormControlProps({
        propDisabled,
        propRequired,
        propId,
        propAriaDisabled,
        propReadOnly,
      });

    const debouncedOnChangeRef = useRef(
      debounce((timeframe: Timeframe | null) => {
        onChangeProp?.(timeframe);
      }, STEPPER_DEBOUNCE_MS),
    );

    // Cancel the debounced call on unmount.
    useEffect(() => {
      const debouncedOnChange = debouncedOnChangeRef.current;
      return () => debouncedOnChange.cancel();
    }, []);

    const [initialState] = useState<TimeframeSelectorState>(() => {
      const value = isControlled ? memoedValue : memoedDefaultValue;

      const error = validate(value, min, max, {
        formMessageDispatch: formFieldMessagesDispatch,
        precision,
        showError: false,
        checkOrder: true,
        ref: timeframeSelectorRef,
        expectedFormat: formatString,
        valueMode: 'timeframeSelector',
        required,
        errorMessages: TIMEFRAMESELECTOR_ERROR_MESSAGES,
      });
      const timeOffset = getTimeOffsetFromInitialValue(
        value,
        'range',
        min,
        max,
        precision,
      );

      return {
        calendarValue: value,
        dateTimeRangePickerTimeframe: value,
        timeframeSelectorTimeframe: value,
        referenceTimeframe: null,
        min,
        max,
        precision,
        isFullDay: false,
        calendarRef,
        dateTimeFromRef,
        dateTimeRangePickerRef,
        timeframeSelectorRef,
        required,
        timeframeSelectorError: error,
        calendarError: error,
        dateTimeRangePickerError: error,
        previousTimeframe: null,
        timeOffset,
        formatString,
      };
    });

    const [store] = useState(() =>
      createTimeframeStore<
        TimeframeSelectorState,
        TimeframeSelectorStoreActions
      >(
        initialState,
        getTimeframeSelectorActions(
          isControlled,
          timeframeSelectorRef,
          formFieldMessagesDispatch,
          onChangeProp,
          debouncedOnChangeRef,
          TIMEFRAMESELECTOR_ERROR_MESSAGES,
        ),
      ),
    );

    useSyncPropsAndState(
      store,
      memoedValue,
      isControlled,
      precision,
      formatString,
      required,
      formFieldMessagesDispatch,
      timeframeSelectorRef,
      debouncedOnChangeRef,
    );

    // Keep min and max updated at midnight
    useMinMaxStoreSync(
      store,
      min,
      max,
      useCallback(
        (
          state: TimeframeSelectorState,
          min: TimeValue | null,
          max: TimeValue | null,
        ) => {
          const error = validate(state.timeframeSelectorTimeframe, min, max, {
            formMessageDispatch: formFieldMessagesDispatch,
            formerError: state.timeframeSelectorError,
            precision: state.precision,
            showError: false,
            checkOrder: true,
            ref: timeframeSelectorRef,
            expectedFormat: state.formatString,
            valueMode: 'timeframeSelector',
            required: state.required,
            errorMessages: TIMEFRAMESELECTOR_ERROR_MESSAGES,
          });
          return {
            timeframeSelectorError: error,
            calendarError: error,
            dateTimeRangePickerError: error,
          };
        },
        [formFieldMessagesDispatch],
      ),
    );

    const mergedRef = useMergeRefs<TimeRangePickerRef>([
      timeframeSelectorRef,
      forwardedRef,
    ]);

    return (
      <TimeframeSelectorStoreProvider store={store}>
        <TimeframeSelectorRoot
          {...remainingProps}
          id={id}
          ref={mergedRef}
          aria-disabled={ariaDisabled}
          disabled={disabled}
          readOnly={readOnly}
        />
      </TimeframeSelectorStoreProvider>
    );
  },
);

(
  _TimeframeSelector as typeof _TimeframeSelector & { displayName: string }
).displayName = 'TimeframeSelector';

/**
*`TimeframeSelector` is a filtering component that lets users choose from preset timeframes or add unique "from" and "to" time values of their own.

* @public
*/
export const TimeframeSelector = Object.assign(_TimeframeSelector, {
  Trigger,
  DisplayValue,
  CustomTrigger,
  Presets,
  PresetItem,
});
